export function generateNetlify(ctx) {
    const redirects = ctx.isSpa
        ? `
[[redirects]]
  from = "/*"
  to = "/index.html"
  status = 200
`
        : '';
    return `# ---------------------------------------------------
# netlify.toml generated by docmd v${ctx.version}
# Project: ${ctx.title}
# https://docmd.io/deployment/netlify
# ---------------------------------------------------

[build]
  command = "npm install -g @docmd/core@${ctx.version} && docmd build"
  publish = "${ctx.outDir}"

[build.environment]
  NODE_VERSION = "20"

[[headers]]
  for = "/assets/*"
  [headers.values]
    Cache-Control = "public, max-age=15552000, immutable"

[[headers]]
  for = "/*.html"
  [headers.values]
    Cache-Control = "public, max-age=0, must-revalidate"
${redirects}`;
}
